    'System.Text.Json': '10.0.8',
    'Microsoft.Extensions.Logging': '10.0.8',
    'Azure.Storage.Blobs': '12.28.0',
    'Microsoft.Extensions.Hosting': '10.0.8',
    'OpenTelemetry.Extensions.Hosting': '1.15.3',
}
# TFM-specific
newtonsoft = {'net8.0': '8.0.27'}

for proj in data['projects']:
    for fw in proj['frameworks']:
        for pkg in fw['topLevelPackages']:
            if pkg['id'] in upgrades:
                pkg['requestedVersion'] = upgrades[pkg['id']]
                pkg['resolvedVersion'] = upgrades[pkg['id']]
            if pkg['id'] == 'Microsoft.AspNetCore.Mvc.NewtonsoftJson' and fw['framework'] in newtonsoft:
                pkg['requestedVersion'] = newtonsoft[fw['framework']]
                pkg['resolvedVersion'] = newtonsoft[fw['framework']]

with open('baseline-packages.json', 'w') as f:
    json.dump(data, f, indent=2)
    f.write('\n')
print('Done')
